import React, { useEffect, useState, useCallback } from 'react';
import {
  Search, Plus, Minus, Trash2, ShoppingCart, Loader, AlertCircle,
  CreditCard, Banknote, ReceiptText, CheckCircle2, X,
} from 'lucide-react';
import api from '../../services/api';

const StaffPOS = () => {
  const [products, setProducts]     = useState([]);
  const [cart, setCart]             = useState([]);
  const [search, setSearch]         = useState('');
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState('');
  const [paying, setPaying]         = useState(false);
  const [successMsg, setSuccessMsg] = useState('');
  const [payMethod, setPayMethod]   = useState('Cash');
  const [tendered, setTendered]     = useState('');

  useEffect(() => {
    api.get('/products')
      .then(r => setProducts(r.data || []))
      .catch(() => setError('Failed to load products'))
      .finally(() => setLoading(false));
  }, []);

  const filtered = products.filter(p =>
    p.productName?.toLowerCase().includes(search.toLowerCase()) ||
    p.barcode?.toLowerCase().includes(search.toLowerCase())
  );

  const addToCart = (product) => {
    setCart(prev => {
      const existing = prev.find(i => i.productId === product.productId);
      if (existing) return prev.map(i => i.productId === product.productId ? { ...i, qty: i.qty + 1 } : i);
      return [...prev, { ...product, qty: 1 }];
    });
  };

  const changeQty = (productId, delta) => {
    setCart(prev =>
      prev.map(i => i.productId === productId ? { ...i, qty: Math.max(1, i.qty + delta) } : i)
    );
  };

  const removeItem = (productId) => setCart(prev => prev.filter(i => i.productId !== productId));

  const subtotal = cart.reduce((a, i) => a + (i.price || i.sellingPrice || 0) * i.qty, 0);
  const change   = parseFloat(tendered || 0) - subtotal;

  const handleCheckout = useCallback(async () => {
    if (cart.length === 0) return;
    setPaying(true);
    try {
      await api.post('/sales', {
        saleDetails: cart.map(i => ({ productId: i.productId, quantity: i.qty, unitPrice: i.price || i.sellingPrice || 0 })),
        paymentMethod: payMethod,
        amountTendered: parseFloat(tendered) || subtotal,
      });
      setCart([]);
      setTendered('');
      setSuccessMsg('Sale completed!');
      setTimeout(() => setSuccessMsg(''), 3000);
    } catch {
      setError('Failed to process sale. Try again.');
      setTimeout(() => setError(''), 4000);
    } finally {
      setPaying(false);
    }
  }, [cart, payMethod, tendered, subtotal]);

  return (
    <div className="flex gap-4 h-[calc(100vh-120px)]">

      {/* ── Products Panel ── */}
      <div className="flex-1 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100">
          <h2 className="font-bold text-slate-800 mb-3 flex items-center gap-2">
            <ShoppingCart className="w-5 h-5 text-emerald-600" /> Point of Sale
          </h2>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search products or scan barcode…"
              className="w-full pl-9 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-400 focus:border-transparent"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          {loading ? (
            <div className="flex items-center justify-center py-16"><Loader className="w-7 h-7 text-emerald-500 animate-spin" /></div>
          ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-4 gap-3">
              {filtered.map(p => (
                <button
                  key={p.productId}
                  onClick={() => addToCart(p)}
                  className="group flex flex-col items-start p-3 bg-slate-50 hover:bg-emerald-50 border border-slate-200 hover:border-emerald-300 rounded-xl text-left transition-all"
                >
                  <div className="w-full h-20 bg-gradient-to-br from-slate-100 to-slate-200 rounded-lg mb-2 flex items-center justify-center overflow-hidden">
                    {p.imageUrl
                      ? <img src={p.imageUrl} alt={p.productName} className="w-full h-full object-cover rounded-lg" />
                      : <ShoppingCart className="w-7 h-7 text-slate-300" />
                    }
                  </div>
                  <p className="text-sm font-semibold text-slate-800 truncate w-full leading-tight">{p.productName}</p>
                  <p className="text-xs text-slate-400 mt-0.5">Stock: {p.stockQuantity ?? '–'}</p>
                  <p className="text-sm font-bold text-emerald-600 mt-1">${(p.price || p.sellingPrice || 0).toFixed(2)}</p>
                </button>
              ))}
              {filtered.length === 0 && (
                <div className="col-span-full text-center py-16 text-slate-400">No products found</div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* ── Cart Panel ── */}
      <div className="w-80 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex items-center justify-between">
          <h2 className="font-bold text-slate-800">Cart</h2>
          <span className="text-xs bg-emerald-100 text-emerald-700 font-semibold px-2 py-0.5 rounded-full">{cart.length} items</span>
        </div>

        {/* Alerts */}
        {(error || successMsg) && (
          <div className={`mx-4 mt-3 p-3 rounded-xl flex items-center gap-2 text-sm ${error ? 'bg-red-50 text-red-700' : 'bg-green-50 text-green-700'}`}>
            {error ? <AlertCircle className="w-4 h-4 flex-shrink-0" /> : <CheckCircle2 className="w-4 h-4 flex-shrink-0" />}
            {error || successMsg}
          </div>
        )}

        {/* Items */}
        <div className="flex-1 overflow-y-auto p-3 space-y-2">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-slate-300 py-10">
              <ShoppingCart className="w-12 h-12 mb-2" />
              <p className="text-sm">Cart is empty</p>
            </div>
          ) : cart.map(item => (
            <div key={item.productId} className="flex items-center gap-2 p-2.5 bg-slate-50 rounded-xl border border-slate-100">
              <div className="flex-1 min-w-0">
                <p className="text-xs font-semibold text-slate-800 truncate">{item.productName}</p>
                <p className="text-xs text-emerald-600 font-bold">${(item.price || item.sellingPrice || 0).toFixed(2)}</p>
              </div>
              <div className="flex items-center gap-1">
                <button onClick={() => changeQty(item.productId, -1)} className="w-6 h-6 rounded-lg bg-slate-200 hover:bg-slate-300 flex items-center justify-center">
                  <Minus className="w-3 h-3" />
                </button>
                <span className="w-6 text-center text-xs font-bold text-slate-700">{item.qty}</span>
                <button onClick={() => changeQty(item.productId, 1)} className="w-6 h-6 rounded-lg bg-emerald-100 hover:bg-emerald-200 flex items-center justify-center text-emerald-700">
                  <Plus className="w-3 h-3" />
                </button>
              </div>
              <button onClick={() => removeItem(item.productId)} className="p-1 text-red-400 hover:text-red-600 transition-colors">
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>

        {/* Totals & Pay */}
        <div className="p-4 border-t border-slate-100 space-y-3">
          <div className="flex justify-between text-sm">
            <span className="text-slate-500">Subtotal</span>
            <span className="font-bold text-slate-800">${subtotal.toFixed(2)}</span>
          </div>

          {/* Payment method */}
          <div className="flex gap-2">
            {['Cash', 'Card'].map(m => (
              <button
                key={m}
                onClick={() => setPayMethod(m)}
                className={`flex-1 flex items-center justify-center gap-1.5 py-2 rounded-xl text-xs font-semibold border transition-all ${payMethod === m ? 'bg-emerald-600 text-white border-emerald-600' : 'border-slate-200 text-slate-600 hover:border-emerald-300'}`}
              >
                {m === 'Cash' ? <Banknote className="w-3.5 h-3.5" /> : <CreditCard className="w-3.5 h-3.5" />}
                {m}
              </button>
            ))}
          </div>

          {payMethod === 'Cash' && (
            <div>
              <label className="text-xs text-slate-500 mb-1 block">Tendered Amount</label>
              <input
                type="number" min={0} value={tendered}
                onChange={e => setTendered(e.target.value)}
                placeholder="0.00"
                className="w-full px-3 py-2 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-emerald-400"
              />
              {tendered && change >= 0 && (
                <p className="text-xs text-emerald-600 font-medium mt-1">Change: ${change.toFixed(2)}</p>
              )}
            </div>
          )}

          <button
            disabled={cart.length === 0 || paying}
            onClick={handleCheckout}
            className="w-full py-3 rounded-xl bg-gradient-to-r from-emerald-600 to-green-500 text-white font-bold text-sm hover:from-emerald-700 hover:to-green-600 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 shadow-lg shadow-emerald-200"
          >
            {paying ? <Loader className="w-4 h-4 animate-spin" /> : <ReceiptText className="w-4 h-4" />}
            {paying ? 'Processing…' : `Pay $${subtotal.toFixed(2)}`}
          </button>

          {cart.length > 0 && (
            <button onClick={() => setCart([])} className="w-full py-2 text-xs text-slate-400 hover:text-red-500 transition-colors flex items-center justify-center gap-1">
              <Trash2 className="w-3.5 h-3.5" /> Clear cart
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default StaffPOS;
